async function testTimelinePlayButton() {
  // Verify the play button exists in the template with correct structure
  const tmpl = templates.get('sailing-app');
  assert(tmpl, 'sailing-app template should exist');

  // Button should be inside the timeline-header div
  assert(tmpl.includes('id="timeline-play-btn"'), 'Template should have play button');
  assert(tmpl.includes('type="button"'), 'Play button should be type=button');

  // Should have a data attribute placeholder for server-side injection
  assert(tmpl.includes('data-play-interval="{{PLAY_INTERVAL_MS}}"'), 'Template should have config placeholder');

  // Button should be between the label and time display in the header
  const headerStart = tmpl.indexOf('class="timeline-header"');
  const btnPos = tmpl.indexOf('id="timeline-play-btn"');
  const timePos = tmpl.indexOf('id="timeline-time"');
  assert(headerStart < btnPos, 'Play button should be inside timeline header');
  assert(btnPos < timePos, 'Play button should come before the time display');
}
